import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import {
  Box,
  Drawer,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  Divider,
  Toolbar,
  Typography,
  useTheme,
  Avatar,
} from '@mui/material';
import DashboardIcon from '@mui/icons-material/Dashboard';
import DescriptionIcon from '@mui/icons-material/Description';
import BarChartIcon from '@mui/icons-material/BarChart';
import SettingsIcon from '@mui/icons-material/Settings';
import HelpIcon from '@mui/icons-material/Help';
import InfoIcon from '@mui/icons-material/Info';
import ChevronLeftIcon from '@mui/icons-material/ChevronLeft';
import IconButton from '@mui/material/IconButton';
import PieChartIcon from '@mui/icons-material/PieChart';
import CategoryIcon from '@mui/icons-material/Category';
import ShowChartIcon from '@mui/icons-material/ShowChart';
import ReceiptIcon from '@mui/icons-material/Receipt';

const drawerWidth = 240;

function Sidebar({ drawerOpen, toggleDrawer }) {
  const theme = useTheme();
  const location = useLocation();

  const mainMenuItems = [
    { text: 'Summary', icon: <PieChartIcon />, path: '/dashboard' },
    { text: 'Transactions', icon: <ReceiptIcon />, path: '/files' },
    { text: 'Statistics', icon: <ShowChartIcon />, path: '/visualizations' },
    { text: 'Products', icon: <DescriptionIcon />, path: '/products' },
    { text: 'Categories', icon: <CategoryIcon />, path: '/categories' },
  ];

  const isActive = (path) => {
    // Match dashboard as the summary page
    if (path === '/dashboard' && location.pathname === '/dashboard') return true;
    // Match files as the transactions page
    if (path === '/files' && location.pathname === '/files') return true;
    // Match visualizations as the statistics page
    if (path === '/visualizations' && location.pathname === '/visualizations') return true;
    // For other paths, exact match
    return location.pathname === path;
  };

  return (
    <Drawer
      variant="permanent"
      open={drawerOpen}
      sx={{
        width: drawerOpen ? drawerWidth : theme.spacing(7),
        flexShrink: 0,
        whiteSpace: 'nowrap',
        boxSizing: 'border-box',
        ...(drawerOpen && {
          '& .MuiDrawer-paper': {
            width: drawerWidth,
            transition: theme.transitions.create('width', {
              easing: theme.transitions.easing.sharp,
              duration: theme.transitions.duration.enteringScreen,
            }),
            boxSizing: 'border-box',
            overflowX: 'hidden',
            backgroundColor: theme.palette.mode === 'light' ? '#FFFFFF' : '#1E1E1E',
          },
        }),
        ...(!drawerOpen && {
          '& .MuiDrawer-paper': {
            transition: theme.transitions.create('width', {
              easing: theme.transitions.easing.sharp,
              duration: theme.transitions.duration.leavingScreen,
            }),
            overflowX: 'hidden',
            width: theme.spacing(7),
            boxSizing: 'border-box',
            backgroundColor: theme.palette.mode === 'light' ? '#FFFFFF' : '#1E1E1E',
          },
        }),
      }}
    >
      <Toolbar
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: drawerOpen ? 'flex-end' : 'center',
          px: [1],
          py: 1,
        }}
      >
        {drawerOpen && (
          <Box sx={{ display: 'flex', alignItems: 'center', width: '100%' }}>
            <Typography
              variant="h6"
              noWrap
              component="div"
              sx={{ 
                flexGrow: 1, 
                fontWeight: 'bold',
                color: theme.palette.primary.main,
                ml: 2,
                fontSize: '1.1rem',
              }}
            >
              Business Dashboard
            </Typography>
            <IconButton onClick={toggleDrawer}>
              <ChevronLeftIcon />
            </IconButton>
          </Box>
        )}
      </Toolbar>
      
      {drawerOpen && (
        <Box 
          sx={{ 
            display: 'flex', 
            flexDirection: 'column', 
            alignItems: 'center',
            p: 2
          }}
        >
          <Avatar 
            sx={{ 
              width: 80, 
              height: 80, 
              mb: 1,
              bgcolor: theme.palette.primary.main,
              boxShadow: '0px 3px 8px rgba(0, 0, 0, 0.15)'
            }}
            alt="Martina Jackson"
            src="/profile-image.jpg"
          />
          <Typography variant="subtitle1" fontWeight={600} sx={{ mt: 1 }}>
            Martina Jackson
          </Typography>
        </Box>
      )}
      
      <Divider sx={{ my: 1 }} />
      
      <List sx={{ px: 1 }}>
        {mainMenuItems.map((item) => (
          <ListItem key={item.text} disablePadding sx={{ display: 'block', mb: 0.5 }}>
            <ListItemButton
              component={Link}
              to={item.path}
              selected={isActive(item.path)}
              sx={{
                minHeight: 48,
                justifyContent: drawerOpen ? 'initial' : 'center',
                px: 2.5,
                py: 1,
                borderRadius: 2,
                backgroundColor: isActive(item.path)
                  ? theme.palette.primary.main
                  : 'transparent',
                '&:hover': {
                  backgroundColor: isActive(item.path)
                    ? theme.palette.primary.main
                    : theme.palette.mode === 'light' 
                      ? 'rgba(0, 0, 0, 0.04)'
                      : 'rgba(255, 255, 255, 0.08)',
                },
              }}
            >
              <ListItemIcon
                sx={{
                  minWidth: 0,
                  mr: drawerOpen ? 2 : 'auto',
                  justifyContent: 'center',
                  color: isActive(item.path)
                    ? '#FFFFFF'
                    : theme.palette.text.secondary,
                }}
              >
                {item.icon}
              </ListItemIcon>
              <ListItemText
                primary={item.text}
                sx={{
                  opacity: drawerOpen ? 1 : 0,
                  color: isActive(item.path)
                    ? '#FFFFFF'
                    : theme.palette.text.primary,
                  '& .MuiTypography-root': {
                    fontWeight: isActive(item.path) ? 600 : 500,
                  }
                }}
              />
            </ListItemButton>
          </ListItem>
        ))}
      </List>
      
      <Box sx={{ flexGrow: 1 }} />
      
      {drawerOpen && (
        <Box 
          sx={{ 
            p: 2, 
            mx: 2, 
            mb: 3, 
            borderRadius: 2,
            bgcolor: 'rgba(142, 36, 170, 0.05)',
            border: '1px solid rgba(142, 36, 170, 0.1)'
          }}
        >
          <Typography variant="subtitle2" fontWeight={600} color="primary" sx={{ mb: 0.5 }}>
            Upgrade to PRO
          </Typography>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 1.5 }}>
            Get access to premium features
          </Typography>
          <Box 
            component="button" 
            sx={{ 
              bgcolor: theme.palette.primary.main,
              color: 'white',
              border: 'none',
              borderRadius: 1.5,
              py: 0.75,
              px: 2,
              width: '100%',
              fontWeight: 600,
              cursor: 'pointer',
              fontSize: '0.875rem',
              '&:hover': {
                bgcolor: theme.palette.primary.dark,
              }
            }}
          >
            Upgrade
          </Box>
        </Box>
      )}
    </Drawer>
  );
}

export default Sidebar;
